import { Component, ViewChild, TemplateRef, AfterViewInit, signal, inject } from '@angular/core';
import { CommonModule, Location } from '@angular/common';
import { ButtonModule } from 'primeng/button';
import { StepperModule } from 'primeng/stepper';
import { TabsModule } from 'primeng/tabs';
import { Step } from '../../../../shared/models/stepper.model';

@Component({
  selector: 'app-store-docs',
  imports: [CommonModule, ButtonModule, StepperModule, TabsModule],
  templateUrl: './app-store-docs.component.html',
  styleUrl: './app-store-docs.component.scss',
})
export class AppStoreDocsComponent implements AfterViewInit {
  // Create an App steps
  @ViewChild('overviewStep') overviewStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('basicInfoStep') basicInfoStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('publishingStep') publishingStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('integrationStep') integrationStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('permissionsStep') permissionsStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('submitStep') submitStep!: TemplateRef<{ $implicit: Step }>;

  // Developer guide steps
  @ViewChild('protocolStep') protocolStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('contextStep') contextStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('apiStep') apiStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('securityStep') securityStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('constraintsStep') constraintsStep!: TemplateRef<{ $implicit: Step }>;

  private readonly location = inject(Location);

  readonly createSteps = signal<Step[]>([]);
  readonly devSteps = signal<Step[]>([]);
  readonly createCurrentStep = signal<number>(1);
  readonly devCurrentStep = signal<number>(1);
  readonly activeTab = signal<string>('create');

  ngAfterViewInit(): void {
    this.createSteps.set([
      { value: 1, header: 'Overview',            content: this.overviewStep,     disableNext: false },
      { value: 2, header: 'Basic Info',          content: this.basicInfoStep,    disableNext: false },
      { value: 3, header: 'Publishing',          content: this.publishingStep,   disableNext: false },
      { value: 4, header: 'Integration Points',  content: this.integrationStep,  disableNext: false },
      { value: 5, header: 'Permissions',         content: this.permissionsStep,  disableNext: false },
      { value: 6, header: 'Review & Submit',     content: this.submitStep,       disableNext: false },
    ]);

    this.devSteps.set([
      { value: 1, header: 'How It Works',        content: this.protocolStep,     disableNext: false },
      { value: 2, header: 'postMessage Protocol',content: this.contextStep,      disableNext: false },
      { value: 3, header: 'Context Data',        content: this.apiStep,          disableNext: false },
      { value: 4, header: 'Using the API',       content: this.securityStep,     disableNext: false },
      { value: 5, header: 'Security & Constraints', content: this.constraintsStep, disableNext: false },
    ]);
  }

  downloadDoc(): void {
    const file = this.activeTab() === 'create'
      ? { path: 'assets/docs/app-store-create-app.md', name: 'app-store-create-app.md' }
      : { path: 'assets/docs/app-store-developer-guide.md', name: 'app-store-developer-guide.md' };
    const a = document.createElement('a');
    a.href = file.path;
    a.download = file.name;
    a.click();
  }

  goBack(): void {
    this.location.back();
  }

  prevStep(steps: Step[], current: number, setter: (v: number) => void): void {
    const idx = steps.findIndex(s => s.value === current);
    if (idx > 0) setter(steps[idx - 1].value);
  }

  nextStep(steps: Step[], current: number, setter: (v: number) => void): void {
    const idx = steps.findIndex(s => s.value === current);
    if (idx < steps.length - 1) setter(steps[idx + 1].value);
  }

  isFirst(steps: Step[], current: number): boolean {
    return steps[0]?.value === current;
  }

  isLast(steps: Step[], current: number): boolean {
    return steps[steps.length - 1]?.value === current;
  }
}
